import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)

export default new Vuex.Store({
  state: {
    token: localStorage.getItem('lims_dd_token') ? localStorage.getItem('lims_dd_token') : ''
  },
  mutations: {
    setToken (state,token) {
      state.token =token;
      localStorage.setItem("lims_dd_token",token.token);     //存储token
    },
    delToken (state) {
      state.token = '';
      localStorage.removeItem("lims_dd_token");    //删除token
    }
  },
  actions: {
  },
  modules: {
  }
})



