import axios from 'axios'
import {
  config
} from '../config'
let app = axios.create()

app.defaults.timeout = 5000; //响应时间
app.defaults.headers.post['Content-Type'] = 'application/json'; //配置请求头
app.defaults.baseURL = `${config.http}${config.devServerPath}`; //配置接口地址

//(添加请求拦截器)
app.interceptors.request.use((config) => {
  // console.log('请求拦截器',config);
  //在发送请求之前做某件事
  // if (config.method === 'post') {
  //   config.data = qs.stringify(config.data);
  // }
  if (localStorage.getItem('token')) {

    config.headers.common['Authorization'] = `Bearer ${localStorage.getItem('token')}` //此处的XX-Token要根据登录接口中请求头的名字来写
  }
  return config;
}, (error) => {
  console.log('错误的传参')
  return Promise.reject(error);
});

//返回状态判断(添加响应拦截器)
app.interceptors.response.use((res) => {
  // console.log('响应拦截器',res);
  //对响应数据做些事
  // console.log(res.data.success);
  if (!res.data.success) {
    return Promise.resolve(res);
  }
  return res;
}, (error) => {
  console.log(('网络异常'));
  return Promise.reject(error);
});

//返回一个Promise(发送post请求)
export function post(url, params) {
  return new Promise((resolve, reject) => {
    app.post(url, params)
      .then(response => {
        resolve(response);
      }, err => {
        reject(err);
      })
      .catch((error) => {
        reject(error)
      })
  })
}
// 返回一个Promise(发送get请求)
export function get(url, param) {
  return new Promise((resolve, reject) => {
    app.get(url, {
        params: param
      })
      .then(response => {
        resolve(response)
      }, err => {
        reject(err)
      })
      .catch((error) => {
        reject(error)
      })
  })
}
export default {
  post,
  get
}